package be.schaubroeck.lpb.rkm.rekenmotor.feestdagen;

import be.schaubroeck.lpb.rkm.feestdagen.VergoedingFeestDagResultaat;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.Admin;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.RekenBedrag;
import be.schaubroeck.lpb.tools.RekenHoofd;
import be.schaubroeck.lpb.tools.RekenLijn;
import be.schaubroeck.lpb.tools.enumtypes.Hoedanigheid;
import be.schaubroeck.lpb.tools.enumtypes.RekenBedragType;
import be.schaubroeck.lpb.tools.service.KalOpdrachtLooncodeService;
import be.schaubroeck.lpb.tools.service.RekenResultatenService;
import be.schaubroeck.temporal.interval.LocalDateInterval;
import com.google.common.collect.Ordering;
import org.joda.time.LocalDate;
import org.springframework.beans.factory.annotation.Autowired;

import java.math.BigDecimal;
import java.util.ArrayList;
import java.util.List;
import java.util.Set;

public class BerekenVergoedingFeestDag {


    private static final BigDecimal PRESTATIE_NOEMER = BigDecimal.valueOf(26);

    private final KalOpdrachtLooncodeService kalOpdrachtLooncodeService;
    private final RekenResultatenService rekenResultatenService;

    @Autowired
    public BerekenVergoedingFeestDag(KalOpdrachtLooncodeService kalOpdrachtLooncodeService, RekenResultatenService rekenResultatenService) {
        this.kalOpdrachtLooncodeService = kalOpdrachtLooncodeService;
        this.rekenResultatenService = rekenResultatenService;
    }

    public List<VergoedingFeestDagResultaat> rekenVergoeding(
            Admin admin, VergoedingFeestDagData basisData, List<Opdracht> opdrachten, LocalDate referteDatum) {
        List<VergoedingFeestDagResultaat> resultaten = new ArrayList<>();

        for (Opdracht opdracht : opdrachten) {
            VergoedingFeestDagResultaat resultaat = rekenVergoeding(admin, basisData, opdracht, referteDatum);
            if (resultaat != null) {
                resultaten.add(resultaat);
            }
        }
        return resultaten;
    }

    public VergoedingFeestDagResultaat rekenVergoeding(Admin admin, VergoedingFeestDagData basisData, Opdracht opdracht, LocalDate referteDatum) {
        VergoedingFeestDagResultaat resultaat = null;
        if (basisData.komtInAanmerking(opdracht, referteDatum) && !vergoedingAanwezigInKalender(admin, opdracht, basisData, referteDatum)) {
            Money effectievePrestaties = bepaalEffectievePrestaties(admin, basisData, opdracht, referteDatum);
            Money bedrag = effectievePrestaties.multiply(basisData.getAantalFeestDagen(opdracht.getHoedanigheid())).divide(PRESTATIE_NOEMER).round(2);
            LocalDate kalenderDatum = bepaalPrestatieKalenderDatum(admin, opdracht, referteDatum);
            if (kalenderDatum != null && bedrag.signum() != 0) {
                AardKodeExtensie loonCode = basisData.getLoonCode(opdracht.getHoedanigheid());
                LocalDate prestatieDatum = Ordering.natural().max(opdracht.getBeginDatum(), kalenderDatum.dayOfMonth().withMinimumValue());
                resultaat = new VergoedingFeestDagResultaat(opdracht, prestatieDatum, referteDatum, loonCode, bedrag);
            }
        }
        return resultaat;
    }

    public Money bepaalEffectievePrestaties(Admin admin, VergoedingFeestDagData basisData, Opdracht opdracht, LocalDate datum) {
        LocalDate referentieDatum = bepaalReferentieDatumEffectievePrestaties(opdracht, datum);
        List<RekenHoofd> hoofden = rekenResultatenService.findByOpdrachtBegindatum(admin, opdracht, referentieDatum);
        return hoofden.stream().filter(hoofd -> hoofd.getRnummer() != null)
                .map(RekenHoofd::getRekenLijnen).flatMap(Set::stream)
                .filter(x -> basisData.isSupplementFeestDag(x.getAardKodeExtensie()))
                .map(RekenLijn::getRekenBedragen).flatMap(Set::stream)
                .filter(rekenBedrag -> rekenBedrag.getBedragType() == RekenBedragType.BRUTO_MAANDLOON)
                .map(RekenBedrag::getBedrag).reduce(Money.ZERO, Money::add);
    }

    private LocalDate bepaalReferentieDatumEffectievePrestaties(Opdracht opdracht, LocalDate datum) {
        int keerTerug = opdracht.getHoedanigheid() == Hoedanigheid.VASTBENOEMDEN ? 3 : 2;
        return datum.minusMonths(keerTerug).dayOfMonth().withMinimumValue();
    }

    private boolean vergoedingAanwezigInKalender(Admin admin, Opdracht opdracht, VergoedingFeestDagData basisData, LocalDate datum) {
        AardKodeExtensie loonCode = basisData.getLoonCode(opdracht.getHoedanigheid());
        return kalOpdrachtLooncodeService.bestaatVoorAkeEnRefMaand(admin, opdracht, loonCode, datum);
    }

    private LocalDate bepaalPrestatieKalenderDatum(Admin admin, Opdracht opdracht, LocalDate datum) {
        LocalDateInterval periode = new LocalDateInterval(datum.withDayOfMonth(1).minusYears(1), datum.dayOfMonth().withMaximumValue());
        return kalOpdrachtLooncodeService.bepaalLaatsteDatumMetPrestatieCodeInPeriode(admin, opdracht, periode, 1);
    }

}
